mapper.select:
SELECT g.group_no, g.group_nm, g.group_cd, cg.code_nm AS group_cd_nm, g.represent_nm, g.manager_nm, g.manager_phone, g.manager_email, (SELECT COUNT(*) FROM tb_member m WHERE m.group_no = g.group_no AND m.status_cd != 'WITHDRAWN') AS current_member_cnt, g.max_member_cnt, g.contract_status_cd, cs.code_nm AS contract_status_nm, DATE_FORMAT(g.contract_start_dt, '%Y-%m-%d') AS contract_start_dt, DATE_FORMAT(g.contract_end_dt, '%Y-%m-%d') AS contract_end_dt, g.monthly_fee FROM tb_member_group g LEFT JOIN tb_com_code cg ON cg.grp_cd = 'GROUP_TYPE_CD' AND cg.code = g.group_cd LEFT JOIN tb_com_code cs ON cs.grp_cd = 'CONTRACT_STATUS_CD' AND cs.code = g.contract_status_cd WHERE 1 = 1 AND g.group_cd = #{searchGroupCd}
AND (g.group_nm LIKE CONCAT('%', #{searchKeyword}, '%') OR g.represent_nm LIKE CONCAT('%', #{searchKeyword}, '%') OR g.manager_nm LIKE CONCAT('%', #{searchKeyword}, '%'))
ORDER BY g.group_no DESC
